mapper.select:
SELECT company_question_id, company_name, job_role, difficulty, question_content, question_type, is_active, created_at, updated_at FROM company_questions WHERE 1 = 1
AND company_name LIKE CONCAT('%', #{companyName}, '%')
AND job_role = #{jobRole}
AND difficulty = #{difficulty}
AND is_active = #{isActive}
ORDER BY created_at DESC
